package com.taskflow.repository;

import com.taskflow.entity.Task;
import com.taskflow.entity.TaskStatus;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest;
import org.springframework.boot.test.autoconfigure.orm.jpa.TestEntityManager;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.PageRequest;
import org.springframework.data.domain.Pageable;

import static org.assertj.core.api.Assertions.assertThat;

@DataJpaTest
@DisplayName("TaskRepository")
class TaskRepositoryTest {

    @Autowired
    private TaskRepository taskRepository;

    @Autowired
    private TestEntityManager entityManager;

    private Task activeTask;
    private Task deletedTask;
    private Task highPriorityTask;
    private Task inProgressTask;

    @BeforeEach
    void setUp() {
        activeTask = new Task();
        activeTask.setTitle("Active Task");
        activeTask.setDescription("An active task");
        activeTask.setPriority("MEDIUM");
        activeTask.setStatus(TaskStatus.TODO);
        activeTask.setCreatedBy(1L);
        activeTask.setDeleted(false);
        entityManager.persistAndFlush(activeTask);

        deletedTask = new Task();
        deletedTask.setTitle("Deleted Task");
        deletedTask.setDescription("A deleted task");
        deletedTask.setPriority("LOW");
        deletedTask.setStatus(TaskStatus.TODO);
        deletedTask.setCreatedBy(1L);
        deletedTask.setDeleted(true);
        entityManager.persistAndFlush(deletedTask);

        highPriorityTask = new Task();
        highPriorityTask.setTitle("Urgent Bug Fix");
        highPriorityTask.setDescription("Fix the critical bug");
        highPriorityTask.setPriority("HIGH");
        highPriorityTask.setStatus(TaskStatus.TODO);
        highPriorityTask.setCreatedBy(2L);
        highPriorityTask.setDeleted(false);
        entityManager.persistAndFlush(highPriorityTask);

        inProgressTask = new Task();
        inProgressTask.setTitle("In Progress Task");
        inProgressTask.setDescription("Currently working on this");
        inProgressTask.setPriority("MEDIUM");
        inProgressTask.setStatus(TaskStatus.IN_PROGRESS);
        inProgressTask.setCreatedBy(1L);
        inProgressTask.setDeleted(false);
        entityManager.persistAndFlush(inProgressTask);

        entityManager.clear();
    }

    // --- findByDeletedFalse ---

    @Test
    @DisplayName("findByDeletedFalse should return only non-deleted tasks")
    void findByDeletedFalseShouldReturnOnlyNonDeletedTasks() {
        Pageable pageable = PageRequest.of(0, 10);
        Page<Task> result = taskRepository.findByDeletedFalse(pageable);

        assertThat(result.getContent()).hasSize(3);
        assertThat(result.getContent()).noneMatch(Task::isDeleted);
    }

    @Test
    @DisplayName("findByDeletedFalse should support pagination")
    void findByDeletedFalseShouldSupportPagination() {
        Pageable pageable = PageRequest.of(0, 2);
        Page<Task> result = taskRepository.findByDeletedFalse(pageable);

        assertThat(result.getContent()).hasSize(2);
        assertThat(result.getTotalElements()).isEqualTo(3);
        assertThat(result.getTotalPages()).isEqualTo(2);
    }

    // --- Keyword search ---

    @Test
    @DisplayName("should search by keyword in title (case-insensitive)")
    void shouldSearchByKeywordInTitleCaseInsensitive() {
        Pageable pageable = PageRequest.of(0, 10);
        Page<Task> result = taskRepository.findByDeletedFalseAndTitleContainingIgnoreCase("urgent", pageable);

        assertThat(result.getContent()).hasSize(1);
        assertThat(result.getContent().get(0).getTitle()).isEqualTo("Urgent Bug Fix");
    }

    @Test
    @DisplayName("should return empty page when keyword does not match")
    void shouldReturnEmptyPageWhenKeywordDoesNotMatch() {
        Pageable pageable = PageRequest.of(0, 10);
        Page<Task> result = taskRepository.findByDeletedFalseAndTitleContainingIgnoreCase("nonexistent", pageable);

        assertThat(result.getContent()).isEmpty();
    }

    @Test
    @DisplayName("keyword search should exclude deleted tasks")
    void keywordSearchShouldExcludeDeletedTasks() {
        Pageable pageable = PageRequest.of(0, 10);
        Page<Task> result = taskRepository.findByDeletedFalseAndTitleContainingIgnoreCase("Deleted", pageable);

        assertThat(result.getContent()).isEmpty();
    }

    // --- Priority filter ---

    @Test
    @DisplayName("should filter by priority")
    void shouldFilterByPriority() {
        Pageable pageable = PageRequest.of(0, 10);
        Page<Task> result = taskRepository.findByDeletedFalseAndPriority("HIGH", pageable);

        assertThat(result.getContent()).hasSize(1);
        assertThat(result.getContent().get(0).getPriority()).isEqualTo("HIGH");
    }

    @Test
    @DisplayName("priority filter should exclude deleted tasks")
    void priorityFilterShouldExcludeDeletedTasks() {
        Pageable pageable = PageRequest.of(0, 10);
        Page<Task> result = taskRepository.findByDeletedFalseAndPriority("LOW", pageable);

        assertThat(result.getContent()).isEmpty();
    }

    // --- Status filter ---

    @Test
    @DisplayName("should filter by status")
    void shouldFilterByStatus() {
        Pageable pageable = PageRequest.of(0, 10);
        Page<Task> result = taskRepository.findByDeletedFalseAndStatus(TaskStatus.IN_PROGRESS, pageable);

        assertThat(result.getContent()).hasSize(1);
        assertThat(result.getContent().get(0).getStatus()).isEqualTo(TaskStatus.IN_PROGRESS);
    }

    @Test
    @DisplayName("status filter should exclude deleted tasks")
    void statusFilterShouldExcludeDeletedTasks() {
        // deletedTask has status TODO, but is deleted
        // so filtering by TODO should return only the active TODO tasks
        Pageable pageable = PageRequest.of(0, 10);
        Page<Task> result = taskRepository.findByDeletedFalseAndStatus(TaskStatus.TODO, pageable);

        assertThat(result.getContent()).hasSize(2); // activeTask + highPriorityTask
        assertThat(result.getContent()).noneMatch(Task::isDeleted);
    }

    // --- Persistence ---

    @Test
    @DisplayName("should auto-generate id on persist")
    void shouldAutoGenerateIdOnPersist() {
        Task task = new Task();
        task.setTitle("New Task");
        task.setPriority("MEDIUM");
        task.setStatus(TaskStatus.TODO);
        task.setCreatedBy(1L);
        task.setDeleted(false);

        Task saved = entityManager.persistAndFlush(task);

        assertThat(saved.getId()).isNotNull();
    }
}

